name: Deploy to GitHub Pages

on:
  push:
    branches:
      - main
  workflow_dispatch:  # Allow manual triggering

permissions:
  contents: read
  pages: write
  id-token: write

concurrency:
  group: "pages"
  cancel-in-progress: false

jobs:
  build:
    runs-on: ubuntu-latest
    steps:
      - name: Checkout
        uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: '18'
          cache: 'npm'

      - name: Install dependencies
        run: npm ci

      - name: Build static site
        run: |
          mkdir -p _site
          # Copy docs files if directory exists
          if [ -d "docs" ]; then
            cp docs/* _site/ 2>/dev/null || echo "No files found in docs directory"
          fi
          # Create index.html if it doesn't exist
          if [ ! -f _site/index.html ]; then
            echo "Creating index.html..."
            cat > _site/index.html << 'EOF'
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Stampcoin Platform</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
            line-height: 1.6;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            min-height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
            padding: 20px;
        }
        .container {
            background: white;
            border-radius: 20px;
            padding: 60px 40px;
            max-width: 800px;
            box-shadow: 0 20px 60px rgba(0,0,0,0.3);
            text-align: center;
        }
        h1 {
            color: #667eea;
            font-size: 3em;
            margin-bottom: 20px;
            font-weight: 700;
        }
        .subtitle {
            color: #666;
            font-size: 1.2em;
            margin-bottom: 30px;
        }
        .description {
            color: #444;
            font-size: 1.1em;
            margin-bottom: 40px;
            line-height: 1.8;
        }
        .features {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
            gap: 20px;
            margin: 40px 0;
            text-align: left;
        }
        .feature {
            padding: 20px;
            background: #f8f9fa;
            border-radius: 10px;
            border-left: 4px solid #667eea;
        }
        .feature h3 {
            color: #667eea;
            margin-bottom: 10px;
        }
        .cta-button {
            display: inline-block;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            color: white;
            padding: 15px 40px;
            border-radius: 30px;
            text-decoration: none;
            font-weight: 600;
            font-size: 1.1em;
            margin-top: 20px;
            transition: transform 0.3s, box-shadow 0.3s;
        }
        .cta-button:hover {
            transform: translateY(-2px);
            box-shadow: 0 10px 20px rgba(102, 126, 234, 0.4);
        }
        .languages {
            margin-top: 40px;
            padding-top: 30px;
            border-top: 2px solid #eee;
            color: #888;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>🎯 Stampcoin Platform</h1>
        <p class="subtitle">منصة رقمية | Digital Platform | Digitale Plattform</p>

        <p class="description">
            An innovative blockchain-based platform for digital stamps, rewards, and loyalty tokens.
            Secure peer-to-peer transfers and a marketplace for digital collectibles.
        </p>

        <div class="features">
            <div class="feature">
                <h3>💳 Digital Wallet</h3>
                <p>Secure storage for your digital stamps and tokens</p>
            </div>
            <div class="feature">
                <h3>🔒 Secure Transfers</h3>
                <p>Blockchain-powered peer-to-peer transactions</p>
            </div>
            <div class="feature">
                <h3>🛍️ Marketplace</h3>
                <p>Buy, sell, and trade digital collectibles</p>
            </div>
            <div class="feature">
                <h3>👤 User Profiles</h3>
                <p>Verified accounts with complete profile management</p>
            </div>
        </div>

        <a href="https://github.com/zedanazad43/stp" class="cta-button">View on GitHub</a>

        <div class="languages">
            <p>🇸🇦 العربية • 🇬🇧 English • 🇩🇪 Deutsch</p>
        </div>
    </div>
</body>
</html>
EOF
          fi

      - name: Setup Pages
        uses: actions/configure-pages@v4

      - name: Upload artifact
        uses: actions/upload-pages-artifact@v3
        with:
          path: ./_site

  deploy:
    environment:
      name: github-pages
      url: ${{ steps.deployment.outputs.page_url }}
    runs-on: ubuntu-latest
    needs: build
    steps:
      - name: Deploy to GitHub Pages
        id: deployment
        uses: actions/deploy-pages@v4

